import React, { useState, useEffect } from "react";
import Nav from "../Nav/Nav";
import "./MyReservations.css";

// Movie trailer mapping - you can expand this as needed
const MOVIE_TRAILERS = {
  'Avatar: The Way of Water': 'https://www.youtube.com/watch?v=d9MyW72ELq0',
  'Elemental': 'https://www.youtube.com/watch?v=hXzcyx9V0xw',
  'Shazam! Fury of the Gods': 'https://www.youtube.com/watch?v=AIc671o9y43',
  'Black Panther: Wakanda Forever': 'https://www.youtube.com/watch?v=RlOB3UALvrQ',
  'Spider-Man: Across the Spider-Verse': 'https://www.youtube.com/watch?v=shW9i6k8cB0',
  'Oppenheimer': 'https://www.youtube.com/watch?v=uYPbbksJxIg',
  'Barbie': 'https://www.youtube.com/watch?v=pBk4NYhWNMM',
  'The Little Mermaid': 'https://www.youtube.com/watch?v=kpGo2_d3oYE',
  'Ant-Man and the Wasp: Quantumania': 'https://www.youtube.com/watch?v=ZlNFpri-Y40'
};

// Function to extract YouTube video ID from URL
const getYouTubeVideoId = (url) => {
  const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
  const match = url.match(regExp);
  return (match && match[2].length === 11) ? match[2] : null;
};

// Function to generate YouTube thumbnail URL
const getYouTubeThumbnail = (url) => {
  const videoId = getYouTubeVideoId(url);
  if (videoId) {
    return `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`;
  }
  return '/img/placeholder-video.jpg';
};

function MyReservations() {
  const [reservations, setReservations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [groupedReservations, setGroupedReservations] = useState({});

  // Fetch reservations from API
  useEffect(() => {
    const fetchReservations = async () => {
      try {
        setLoading(true);
        // For demo purposes, we'll fetch all reservations
        // In a real app, you'd filter by user email
        const response = await fetch('http://localhost:5000/api/reservations');
        const data = await response.json();
        
        if (data.success) {
          setReservations(data.data);
          // Group reservations by movie name
          const grouped = data.data.reduce((acc, reservation) => {
            const movieName = reservation.movie_name;
            if (!acc[movieName]) {
              acc[movieName] = [];
            }
            acc[movieName].push(reservation);
            return acc;
          }, {});
          setGroupedReservations(grouped);
        } else {
          console.error('Error fetching reservations:', data.message);
          // Fallback to empty array if API fails
          setReservations([]);
        }
      } catch (error) {
        console.error('Error fetching reservations:', error);
        // Fallback to empty array if API fails
        setReservations([]);
      } finally {
        setLoading(false);
      }
    };

    fetchReservations();
  }, []);

  const handleCancelReservation = async (reservationId) => {
    try {
      const response = await fetch(`http://localhost:5000/api/reservations/${reservationId}/status`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ status: 'cancelled' })
      });

      const data = await response.json();
      
      if (data.success) {
        // Update local state
        setReservations(reservations.map(res => 
          res._id === reservationId 
            ? { ...res, status: 'cancelled' }
            : res
        ));
        alert("Reservation cancelled successfully!");
      } else {
        alert('Error cancelling reservation: ' + data.message);
      }
    } catch (error) {
      console.error('Error cancelling reservation:', error);
      alert('Error cancelling reservation. Please try again.');
    }
  };

  return (
    <div>
      {/* Navbar */}
      <Nav />

      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>My Reservations</h1>
          <p>Manage your cinema bookings and reservations</p>
        </div>
      </section>

      {/* Reservations Section */}
      <section className="reservations-section">
        <div className="container">
          <h2>Your Bookings</h2>
          
          {loading ? (
            <div className="loading">Loading your reservations...</div>
          ) : reservations.length === 0 ? (
            <div className="no-reservations">
              <h3>No reservations found</h3>
              <p>You haven't made any reservations yet.</p>
              <a href="/new-reservation" className="cta-btn">Make a Reservation</a>
            </div>
          ) : (
            <div className="movie-groups">
              {Object.entries(groupedReservations).map(([movieName, movieReservations]) => {
                const trailerUrl = MOVIE_TRAILERS[movieName];
                const totalCost = movieReservations.reduce((sum, res) => sum + (res.total_amount || 0), 0);
                const totalSlots = movieReservations.reduce((sum, res) => sum + res.advertisement_slots.length, 0);
                
                return (
                  <div key={movieName} className="movie-group">
                    <div className="movie-header">
                      <div className="movie-poster">
                        {trailerUrl ? (
                          <div className="video-thumbnail" onClick={() => window.open(trailerUrl, '_blank')}>
                            <img src={getYouTubeThumbnail(trailerUrl)} alt={movieName} />
                            <div className="play-button">
                              <i className="fa fa-play"></i>
                            </div>
                          </div>
                        ) : (
                          <div className="placeholder-poster">
                            <i className="fa fa-film"></i>
                          </div>
                        )}
                      </div>
                      <div className="movie-info">
                        <h3>{movieName}</h3>
                        <div className="movie-stats">
                          <div className="stat-item">
                            <span className="stat-label">Total Reservations:</span>
                            <span className="stat-value">{movieReservations.length}</span>
                          </div>
                          <div className="stat-item">
                            <span className="stat-label">Total Slots:</span>
                            <span className="stat-value">{totalSlots}</span>
                          </div>
                          <div className="stat-item">
                            <span className="stat-label">Total Cost:</span>
                            <span className="stat-value price">₹{totalCost.toLocaleString()}</span>
                          </div>
                        </div>
                      </div>
                    </div>
                    
                    <div className="reservations-list">
                      {movieReservations.map((reservation) => (
                        <div key={reservation._id} className="reservation-card">
                          <div className="reservation-header">
                            <div className="reservation-id">
                              <span className="label">Reservation ID:</span>
                              <span className="value">{reservation.reservation_id}</span>
                            </div>
                            <span className={`status ${reservation.status.toLowerCase()}`}>
                              {reservation.status}
                            </span>
                          </div>
                          
                          <div className="reservation-details">
                            <div className="cinema-info">
                              <h4>{reservation.cinema_name}</h4>
                              <p className="location">{reservation.cinema_location}</p>
                            </div>
                            
                            <div className="reservation-meta">
                              <div className="meta-item">
                                <span className="label">Date:</span>
                                <span className="value">{new Date(reservation.show_date).toLocaleDateString()}</span>
                              </div>
                              <div className="meta-item">
                                <span className="label">Time:</span>
                                <span className="value">{reservation.show_time}</span>
                              </div>
                              <div className="meta-item">
                                <span className="label">Slots:</span>
                                <span className="value">{reservation.advertisement_slots.length}</span>
                              </div>
                              <div className="meta-item">
                                <span className="label">Duration:</span>
                                <span className="value">{reservation.advertisement_duration}s</span>
                              </div>
                              <div className="meta-item">
                                <span className="label">Company:</span>
                                <span className="value">{reservation.company_name}</span>
                              </div>
                              <div className="meta-item">
                                <span className="label">Total:</span>
                                <span className="value price">₹{reservation.total_amount}</span>
                              </div>
                            </div>
                          </div>
                          
                          <div className="reservation-actions">
                            <button className="btn-secondary">View Details</button>
                            {reservation.status !== 'cancelled' && reservation.status !== 'completed' && (
                              <button 
                                className="btn-danger"
                                onClick={() => handleCancelReservation(reservation._id)}
                              >
                                Cancel
                              </button>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <h3>D&S Creations</h3>
            <p>Your premier destination for cinema advertising and entertainment.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul>
              <li><a href="/mainhome">Home</a></li>
              <li><a href="/new-reservation">New Reservation</a></li>
              <li><a href="/my-reservations">My Reservations</a></li>
              <li><a href="/conus">Contact Us</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Contact Info</h4>
            <p>Email: info@dscreations.com</p>
            <p>Phone: +1 (555) 123-4567</p>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; {new Date().getFullYear()} D&S Creations. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
}

export default MyReservations;
